class PeekingIterator implements Iterator<Integer> {
    Integer next = null;
    Iterator<Integer> curr;
    boolean done = false;
	public PeekingIterator(Iterator<Integer> iterator) {
	    curr = iterator;
        moveIterator();
	}

	public Integer peek() {
        return next;
	}

	@Override
	public Integer next() {
        if(done){
            throw new NoSuchElementException();
        }
        Integer res = next;
        moveIterator();

        return res;
	}

	@Override
	public boolean hasNext() {
	    return next!=null;
	}

    public void moveIterator(){
        if(curr.hasNext()){
            next = curr.next();
        }
        else{
            done = true;
            next = null;
        }
    }
}

