static class MergingIterator implements Iterator<Integer> {
        // main idea: it is similar to merge K sorted array -> int[]{iterator_index, iterator_value}, minHeap
        // beginning: add all first elements of the iterator
        // middle: pop out the smallest one, and use i.hasNext() to determine whether or not using i.next()
        // Check overall hasNext() -> minHeap.s empty or not

        List<Iterator<Integer>> iterators;
        PriorityQueue<Integer[]> minHeap;

        public MergingIterator(List<Iterator<Integer>> iterators) {
            this.iterators = iterators;
            minHeap = new PriorityQueue<>((o1, o2) -> {
                if(o1[1].equals(o2[1])){
                    return 0;
                }

                return o1[1] < o2[1] ? -1 : 1;
            });

            for(int i = 0; i < iterators.size(); i++) {
                if(iterators.get(i).hasNext()){
                    minHeap.add(new Integer[]{i,iterators.get(i).next()});
                }

            }

        }


        @Override
        public boolean hasNext() {
            return !minHeap.isEmpty();
        }

        @Override
        public Integer next() {
            Integer[] cur = minHeap.poll();
            Integer result = cur[1];

            if(iterators.get(cur[0]).hasNext()) {
                minHeap.add(new Integer[]{cur[0], iterators.get(cur[0]).next()});
            }

            return result; 
        }
    }
