C++ Solution using heap and map 
```
#include <iostream>
#include <queue>
#include <map>
using namespace std;
typedef vector<int>::iterator vector_iterator;
class MergeIterator{
    private:
        priority_queue<pair<int,vector_iterator>, vector<pair<int,vector_iterator>>, greater<pair<int,vector_iterator>>> min_heap;
        map<vector_iterator,vector_iterator> mp;
    public:
        MergeIterator(vector<vector<int>> &list_of_arrays){
            for(int i=0;i<list_of_arrays.size();i++)
            {
                vector_iterator start = list_of_arrays[i].begin();
                vector_iterator end = list_of_arrays[i].end();
                mp[start] = end;
                if(start != end){
                    min_heap.push(make_pair(*start, start));
                }   
            }
        }

        int next(){
           if(hasNext()){
                pair<int, vector_iterator> top = min_heap.top();
                min_heap.pop();
                vector_iterator curr = top.second;
                vector_iterator end = mp[curr];
                mp.erase(curr);
                int val = top.first;

                if(++curr != end){
                    min_heap.push(make_pair(*curr,curr));
                    mp[curr] = end;
                }
                return val;
            }
           throw out_of_range("list is empty");
        }

        bool hasNext(){
            if(!min_heap.empty())
                return true;
            return false;
        }
};
